def _u(value: str) -> str:
    return value.encode("ascii").decode("unicode_escape")


def _fill(template: str, values: dict[str, str]) -> str:
    for key in sorted(values, key=len, reverse=True):
        value = values[key]
        template = template.replace("@" + key + "@", value)
        template = template.replace("@" + key, value)
    return template



